INSERT INTO food (food_name, price, calories, weight, ingredients, description, front_image_address, back_image_address, category_id) VALUES
('Салатик-бурмалдатик', 200.00, 86.00, 225.00, 'Сыр Фета, вяленая свекла, листья салата, посыпка из чипсов Lays с крабом', 'Такую бурмалду не купишь за деньги, её надо заслужить!', '/IMG/Food/Салатик-бурмалдатик_front.jpg', '/IMG/Food/Салатик-бурмалдатик_back.jpg', 6),
('Чикагский пряник', 150.00, 370.00, 130.00, 'Фруктовое повидло, орешки, сахарная глазурь.', 'Чикагский пряник с начинкой из фруктового повидла, покрытый тонкой белесой гладью сахарной глазури.', '/IMG/Food/Чикагский_пряник_front.jpg', '/IMG/Food/Чикагский_пряник_back.jpg', 2),
('Сладкие палочки от Олега Кизару', 230.00, 560.00, 200.00, 'Вафля, сахар, сгущенка', 'Хорошая работа Олег, очень, ОЧЕНЬ вкусные палочки!', '/IMG/Food/Сладкие_палочки_от_Олега_Кизару_front.jpg', '/IMG/Food/Сладкие_палочки_от_Олега_Кизару_back.jpg', 2),
('Пицца 4к', 750.00, 310.00, 1115.00, 'Черное тонированное тесто, грибы шампиньоны, креветки, 4 вида сыра, томатная паста, фирменный соус', 'Вкусная пицца для тех кто любит когда черная девять на штампах', '/IMG/Food/Пицца_4к_front.jpg', '/IMG/Food/Пицца_4к_back.jpg', 1),
('Молодые томатики', 670.00, 231.00, 967.00, 'Вкусные молодые томатики, выращенные на грядках прекрасного острова в тихом океане, вяленая ветчина, сыр пармезан, базилик и вкуснейший чесночный соус', 'Попробуй эту пиццу, и почувствуй себя миллиардером на своем личном острове!', '/IMG/Food/Молодые_томатики_front.jpg', '/IMG/Food/Молодые_томатики_back.jpg', 1),
('Пэпэронни', 870.00, 280.00, 1250.00, 'Сыр, томатная паста и колбаски пеперонни', 'Фа пэпэ очень пэпэ пицца фа ватафа, попробуй шнене', '/IMG/Food/Пэпэронни_front.jpg', '/IMG/Food/Пэпэронни_back.jpg', 1),
('Борщезолик', 435.00, 60.00, 450.00, 'Свинина, капуста белокочанная, свёкла, картофель, лук репчатый, морковь, помидоры, майонез и сметана по выбору', 'Умопомрачительное сочетание ингредиентов образует это прекрасное блюдо, которое стоит попробовать каждому, кто любит домашнюю кухню и не пьет кока-колу!', '/IMG/Food/Борщезолик_front.jpg', '/IMG/Food/Борщезолик_back.jpg', 5),
('Шаурма от шефа', 310.00, 230.00, 560.00, 'Свинина, лаваш, маринованный лук, помидоры, аджика, майонез, капуста, огурцы свежие, чеснок, растительное масло, специи для шаурмы, соль, перец, зелень (петрушка, укроп), сыр, корнишоны и фирменный соус от маэстро', 'Шаурма или гелентваген? Что выберешь ты? Эту шаурму наш шеф ел с самого детства, и этот рецепт передавался из поколения в поколение в его семье, теперь и вы можете оценить данное произведение кулинарного искусства', '/IMG/Food/Шаурма_от_шефа_front.jpg', '/IMG/Food/Шаурма_от_шефа_back.jpg', 7),
('Раф на миндальном молочке', 228.00, 100.00, 400.00, 'Кофе (эспрессо), миндальное молоко, миндальный сироп, ванильный сахар, миндальные лепестки для украшения.', 'Когда у меня просили пояснить за генгста, я смог ответить, налив своему оппоненту чашечку прекрасного рафа, выпей тоже, и также как и я, поясни всё о чем только спросят. P.S. ICEGERGERT', '/IMG/Food/Раф_на_миндальном_молочке_front.jpg', '/IMG/Food/Раф_на_миндальном_молочке_back.jpg', 3),
('Газированный напиток Lit Energy', 120.00, 70.00, 449.00, 'Сок фейхоа, сахар, газированная вода', 'Сам Михаил Литвин просил нас, чтобы в нашем меню появилось сиё чудо света, чтобы все посетители смогли ощутить себя едущими в М5 F90. Санечка снимаешь!?!', '/IMG/Food/Газированный_напиток_Lit_Energy_front.jpg', '/IMG/Food/Газированный_напиток_Lit_Energy_back.jpg', 3),
('Блины блинские', 300.00, 150.00, 225.00, 'Четыре вида творожка, отборный изюм, сметана и листик мяты как украшение, мука, сахар', 'Эти блинчики пробовал сам Криштиану Роналду, и они ему настолько понравились, что он попросил стать их амбассадором', '/IMG/Food/Блины_блинские_front.jpg', '/IMG/Food/Блины_блинские_back.jpg', 2),
('Сырники фирменные', 500.00, 170.00, 450.00, 'Четыре вида творога, малина, посыпка, изюм, кленовый сироп и секретный ингредиент', 'Фамильный рецепт самого Лионеля Месси, который он любезно предоставил нашему уютному кафе для того, чтобы каждый мог ощутить себя частью семьи величайшего футболиста современности', '/IMG/Food/Сырники_фирменные_front.jpg', '/IMG/Food/Сырники_фирменные_back.jpg', 2),
('Пицца для настоящих мужчин', 950.00, 267.00, 1300.00, 'Ананас, курица, томаты, сыр, творожный соус и сила мегарыцаря', 'Если ты настоящий мужчина, играющий в клеш рояль мегарыцарем и элитными братьями, то ты обязан вкусить этот божественный дар от самих SUPERCELL', '/IMG/Food/Пицца_для_настоящих_мужчин_front.jpg', '/IMG/Food/Пицца_для_настоящих_мужчин_back.jpg', 1),
('Том-Ям', 445.00, 70.00, 350.00, 'Куриный бульон, креветки тигровые, шиитаке, лемонграсс, галангал, листья кафрского лайма, перец чили, рыбный соус, сок лайма.', 'Это Том Ям, детка. Острый как мои треки, горячий как наши тусовки. Ты хотела love story? Получи любовь с первой ложки. Крид рекомендует - не будь пресной!', '/IMG/Food/Том-Ям_front.jpg', '/IMG/Food/Том-Ям_back.jpg', 5),
('Чесночный соус', 49.00, 7.00, 30.00, 'Сочный чесночек прямо с грядки, майонез собственного приготовления из вкусных яичек', 'У меня был блэк стар, этот соус будет уайт стар', '/IMG/Food/Чесночный_соус_front.jpg', '/IMG/Food/Чесночный_соус_back.jpg', 8),
('Кисло-сладкий соус', 49.00, 7.00, 30.00, 'Лимонный сок, специи, абрикосовое пюре, соль, томатная паста, уксус, сахар, вода', 'Слушай, брат. Здесь баланс как в моем бизнесе - дерзкая кислинка и уверенная сладость. Оттеняет мясо, но не перебивает базар. Макай смело - это соус для тех, кто на стиле.', '/IMG/Food/Кисло-сладкий_соус_front.jpg', '/IMG/Food/Кисло-сладкий_соус_back.jpg', 8),
('Сырный', 49.00, 7.00, 30.00, 'Сры чеддер (плавленный), вода, растительное масло, сырный порошок, соль, сахар', 'Нежный, плотный, дорогой — как премиум-трек. Никакого дешёвого сырного порошка, только вкус, от которого реально тащит. Макай наггетсы — и ты в VIP-зоне, даже если сидишь на районе.', '/IMG/Food/Сырный_front.jpg', '/IMG/Food/Сырный_back.jpg', 8),
('Кетчуп', 49.00, 7.00, 30.00, 'Томатная паста, вода, сахар, специи, уксус, соль', 'Чёрная звезда среди соусов. Никаких компромиссов — плотный, насыщенный, без соплей. Макаешь — и чувствуешь: это легитимный томатный вайб. Не как у всех, это как кетчуп, только Boss', '/IMG/Food/Кетчуп_front.jpg', '/IMG/Food/Кетчуп_back.jpg', 8),
('Цезарь', 350.00, 75.00, 225.00, 'Листья салата, курица, сухарики, сыр, томаты, соус цезарь', 'ПРИШЕЛ. УВИДЕЛ. ПОЕЛ.', '/IMG/Food/Цезарь_front.jpg', '/IMG/Food/Цезарь_back.jpg', 6),
('Toxi$ x Fruit Salad', 300.00, 120.00, 250.00, 'Клубника, черника, киви, мандарин, ананас, ежевика, малина, арбуз, сироп, листья мяты', 'Залито сиропом, от которого слипнется не только во рту, но и в голове. Я добавил туда мяту, чтобы ты думал что всё легально. Но после третьей ложки ты поймешь - это гастрономический криминал!', '/IMG/Food/Toxi$_x_Fruit_Salad_front.jpg', '/IMG/Food/Toxi$_x_Fruit_Salad_back.jpg', 6),
('Вайперр', 450.00, 120.00, 400.00, 'Две сочных булочки, говяжья котлета, помидоры, листья салата, лук репчатый, огурцы маринованные, кетчуп + майонез', 'Йо, это Вопер. Сочная говядина, сыр, хруст — всё по кайфу. Соус льётся, будто бит качает. Сделал заказ — сидишь, жуёшь, кайфуешь. Вайб вышел покушать.', '/IMG/Food/Вайперр_front.jpg', '/IMG/Food/Вайперр_back.jpg', 4),
('Имбовые сырки', 120.00, 50.00, 50.00, 'Шоколад, фирменный творог, сгущенное молоко', 'Хочешь реакцию как у Саши S1mple? Кушай сырочек и поднимай глобала', '/IMG/Food/Имбовые_сырки_front.jpg', '/IMG/Food/Имбовые_сырки_back.jpg', 2),
('Куриные ножки', 160.00, 110.00, 250.00, 'Куриное бедро, панировка, специи, паприка', 'Слушай сюда, малыш. Это куриная ножка размером с мой кроссовок. Хруст такой, что слышно на трибунах. Сочная, горячая — как мой данк в плей-офф. Взял одну — снёс голод под щит. Не играй с этим, просто ешь и доминируй. Shaq dunked this chicken', '/IMG/Food/Куриные_ножки_front.jpg', '/IMG/Food/Куриные_ножки_back.jpg', 7),
('Наполеон', 300.00, 372.00, 150.00, 'Коржи, заварной крем, посыпка, сахарная пудра', 'Мой торт. Моя империя вкуса. Тысяча тончайших слоёв — как моя тактика при Аустерлице. Нежный крем пропитывает каждый пласт, как слава — моё имя. Никаких компромиссов. Хочешь кусок? Заслужи. Этот десерт не для plebe. Откусил и молчи. Я сказал — торт велик. Vive l''Empereur. Vive le Napoleon.', '/IMG/Food/Наполеон_front.jpg', '/IMG/Food/Наполеон_back.jpg', 2),
('Шашлык свинной', 500.00, 400.00, 500.00, 'Свинина, лук, перец, соль', 'Ешь вкусный шашлык, соблюдай дисциплину и никогда не нарушай закон.', '/IMG/Food/Шашлык_свиной_front.jpg', '/IMG/Food/Шашлык_свиной_back.jpg', 7),
('Гематоген', 50.00, 10.00, 50.00, 'Бычья кровь, сгущенное молоко с сахаром, ванилин, крахмальная патока, шоколадная глазурь', 'Скушай гематогенку - стань умным человеком в очках!', '/IMG/Food/Гематоген_front.jpg', '/IMG/Food/Гематоген_back.jpg', 2),
('Солянка', 300.00, 200.00, 300.00, 'Бульон на говядине, ветчина, сосиски, охотничьи колбаски, лук, огурцы, томатная паста, каперсы, маслины, рассол огуречный, укроп, сметана', 'дэб', '/IMG/Food/Солянка_front.jpg', '/IMG/Food/Солянка_back.jpg', 5),
('Чебурек армянский', 130.00, 270.00, 200.00, 'Тесто, фарш говяжий, лук, бульон, соль, перец, зелень', 'Брат, лови от Майкла (того самого, что «Пи-и-и-итер» и обожает пожрать): Йоу, чувак, отложи свой гамбургер. Это чебурек. Настоящий. С пузырями, которые лопаются громче, чем Тамара Ивановна орёт на пары. Тесто хрустит, как моя нервная система после сессии, а внутри — бульон, который обжигает губы, будто Кузя психанул. Ты кусаешь — сок течёт по рукам, по подбородку... кайф! Словно стипендия пришла, но ты её уже проел. Не ссы, бери салфетки и в бой. Питер, двигайся — чебурек идёт!', '/IMG/Food/Чебурек_армянский_front.jpg', '/IMG/Food/Чебурек_армянский_back.jpg', 7),
('Картофель фри', 100.00, 312.00, 200.00, 'Картофель, соль', 'Попробуй съесть этот картофель фри быстрее, чем Асхаб Тамаев, и получи в подарок новенькую BMW совершенно бесплатно (Асхаб сдул всю картошку за 0.000001 секунду)', '/IMG/Food/Картофель_фри_front.jpg', '/IMG/Food/Картофель_фри_back.jpg', 7),
('Вегетарианский бургер', 400.00, 180.00, 300.00, 'Булочки, котлета из соевого мяса, лист салата, томаты, огурчики', 'После того как Кайри Ирвинг попробовал этот бургер, он не смог удержаться от того, чтобы забрать чемпионство NBA!', '/IMG/Food/Вегетарианский_бургер_front.jpg', '/IMG/Food/Вегетарианский_бургер_back.jpg', 4),
('Макангеттсы', 120.00, 234.00, 200.00, 'Курица, панировка, соль, перец, паприка', 'Мало кто знает, но между сессиями на студии и тренировками по боксу, лучший музыкант всех времен любит заглянуть в наше маленькое кафе, и взять себе фирменные наггетсы, вот мы и решили сделать коллаборацию вместе с ним!', '/IMG/Food/Макангеттсы_front.jpg', '/IMG/Food/Макангеттсы_back.jpg', 7);